import java.util.*;

class Solution {
    public int minCost(int maxTime, int[][] edges, int[] passingFees) {
        int n = passingFees.length;
        List<List<int[]>> graph = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }
        for (int[] edge : edges) {
            graph.get(edge[0]).add(new int[]{edge[1], edge[2]});
            graph.get(edge[1]).add(new int[]{edge[0], edge[2]});
        }

        int[][] dp = new int[n][maxTime + 1];
        for (int i = 0; i < n; i++) {
            Arrays.fill(dp[i], Integer.MAX_VALUE);
        }
        dp[0][0] = passingFees[0];

        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(arr -> arr[2]));
        pq.offer(new int[]{0, 0, passingFees[0]});

        while (!pq.isEmpty()) {
            int[] cur = pq.poll();
            int time = cur[0], city = cur[1], cost = cur[2];
            if (city == n - 1) {
                return cost;
            }

            for (int[] neighbor : graph.get(city)) {
                int next_time = time + neighbor[1];
                if (next_time > maxTime) continue;

                int new_cost = cost + passingFees[neighbor[0]];
                if (new_cost < dp[neighbor[0]][next_time]) {
                    dp[neighbor[0]][next_time] = new_cost;
                    pq.offer(new int[]{next_time, neighbor[0], new_cost});
                }
            }
        }
        return -1;
    }
}
```

